// === SUCCESSCASTING WEBHOOK SIGNATURE VERIFICATION ===
const crypto = require('crypto');
const headers = $input.item.json.headers || {};
const platform = $input.item.json.platform || 'unknown';
const rawBody = $input.item.json.body || $input.item.json.payload || {};
const allowUnsigned = String($env.FACTORY_WEBHOOK_ALLOW_UNSIGNED || 'false').toLowerCase() === 'true';

function h(name) { return headers[name] || headers[name.toLowerCase()] || headers[name.toUpperCase()]; }
function hmac(secret, body, prefix='') {
  return prefix + crypto.createHmac('sha256', secret).update(typeof body === 'string' ? body : JSON.stringify(body)).digest('hex');
}
const secretMap = {
  shopee: $env.SHOPEE_APP_SECRET || '',
  lazada: $env.LAZADA_APP_SECRET || '',
  tiktok: $env.TIKTOK_APP_SECRET || '',
  facebook: $env.FB_APP_SECRET || ''
};
const secret = secretMap[platform] || '';
let verified = false;
let reason = 'missing_signature';

if (!secret && allowUnsigned) {
  verified = true;
  reason = 'unsigned_allowed_bootstrap_mode';
} else if (platform === 'shopee') {
  const sig = h('x-shopee-signature');
  verified = !!sig && sig === hmac(secret, rawBody);
  reason = verified ? 'hmac_ok' : 'hmac_failed';
} else if (platform === 'facebook') {
  const sig = h('x-hub-signature-256');
  verified = !!sig && sig === hmac(secret, rawBody, 'sha256=');
  reason = verified ? 'hmac_ok' : 'hmac_failed';
} else if (platform === 'lazada') {
  verified = !!h('x-lazada-signature') || (!!secret && !!h('authorization'));
  reason = verified ? 'signature_present' : 'missing_signature';
} else if (platform === 'tiktok') {
  verified = !!h('x-tts-signature');
  reason = verified ? 'signature_present' : 'missing_signature';
} else {
  verified = allowUnsigned;
  reason = verified ? 'unknown_platform_allowed' : 'unknown_platform';
}

return { json: { platform, verified, verify_reason: reason, payload: rawBody, receivedAt: new Date().toISOString(), headers } };

// === NORMALIZE ORDER DATA ===
// Convert platform-specific order format to unified schema
const platform = $input.item.json.platform;
const payload = $input.item.json.payload;

const normalizers = {
  shopee: (data) => ({
    platform_order_id: data.order_sn || data.order_id,
    platform: 'shopee',
    status: data.order_status || 'new',
    customer: {
      name: data.buyer_username || '',
      address: data.shipping_address || {}
    },
    items: (data.item_list || []).map(item => ({
      sku: item.model_sku || item.item_sku,
      name: item.model_name || item.item_name,
      quantity: item.model_quantity_purchased || 1,
      price: (item.model_original_price || 0) / 100,
      platform_price: (item.model_discounted_price || item.model_original_price || 0) / 100
    })),
    total_amount: (data.total_amount || 0) / 100,
    currency: data.currency || 'THB',
    created_at: data.create_time ? new Date(data.create_time * 1000).toISOString() : new Date().toISOString()
  }),

  lazada: (data) => ({
    platform_order_id: data.order_id || data.order_number,
    platform: 'lazada',
    status: data.statuses ? data.statuses[0] : 'new',
    customer: {
      name: data.address_shipping?.first_name + ' ' + (data.address_shipping?.last_name || ''),
      address: data.address_shipping || {}
    },
    items: (data.order_items || data.items || []).map(item => ({
      sku: item.sku || item.seller_sku,
      name: item.name,
      quantity: item.quantity || 1,
      price: parseFloat(item.item_price || 0),
      platform_price: parseFloat(item.paid_price || item.item_price || 0)
    })),
    total_amount: parseFloat(data.price || data.grand_total || 0),
    currency: data.currency || 'THB',
    created_at: data.created_at || new Date().toISOString()
  }),

  tiktok: (data) => ({
    platform_order_id: data.order_id,
    platform: 'tiktok',
    status: data.order_status || 'new',
    customer: {
      name: data.buyer_email || '',
      address: data.shipping_address || {}
    },
    items: (data.order_line_list || []).map(item => ({
      sku: item.seller_sku || item.product_id,
      name: item.product_name,
      quantity: item.quantity || 1,
      price: parseFloat(item.original_price || 0),
      platform_price: parseFloat(item.sale_price || item.original_price || 0)
    })),
    total_amount: parseFloat(data.payment?.total_amount || data.total_amount || 0),
    currency: data.currency || 'THB',
    created_at: data.create_time ? new Date(parseInt(data.create_time) * 1000).toISOString() : new Date().toISOString()
  }),

  facebook: (data) => ({
    platform_order_id: data.id || data.order_id,
    platform: 'facebook',
    status: data.order_status || data.status || 'new',
    customer: {
      name: data.buyer?.name || '',
      address: data.shipping_address || {}
    },
    items: (data.items || data.line_items || []).map(item => ({
      sku: item.retailer_id || item.product_id,
      name: item.name || item.title,
      quantity: item.quantity || 1,
      price: parseFloat(item.price?.amount || item.unit_price || 0),
      platform_price: parseFloat(item.price?.amount || item.unit_price || 0)
    })),
    total_amount: parseFloat(data.total?.amount || data.total_price || 0),
    currency: data.total?.currency || data.currency || 'THB',
    created_at: data.created_time || new Date().toISOString()
  })
};

const normalize = normalizers[platform];
if (!normalize) {
  throw new Error(`Unsupported platform: ${platform}`);
}

const order = normalize(payload);

// Validation
const errors = [];
if (!order.platform_order_id) errors.push('Missing order ID');
if (!order.items || order.items.length === 0) errors.push('No items in order');
if (order.total_amount <= 0) errors.push('Invalid total amount');

return {
  json: {
    ...order,
    _validation: {
      valid: errors.length === 0,
      errors,
      normalized_at: new Date().toISOString()
    }
  }
};

// === STOCK DEDUCTION LOGIC ===
const order = $input.item.json;
const items = order.items || [];

// Calculate stock to deduct per SKU
const deductions = items.map(item => ({
  sku: item.sku,
  quantity: item.quantity,
  platform: order.platform,
  order_id: order.platform_order_id
}));

return {
  json: {
    deductions,
    platform: order.platform,
    order_id: order.platform_order_id,
    total_items: items.reduce((sum, i) => sum + i.quantity, 0),
    processed_at: new Date().toISOString()
  }
};

