// === STOCK ALLOCATION ENGINE ===
// Calculate available stock per platform
const products = $input.all().map(i => i.json);
const SAFETY_STOCK_PERCENT = 0.1;
const ALLOCATION = {
  shopee: 0.35,
  lazada: 0.30,
  tiktok: 0.20,
  facebook: 0.15
};

const syncTasks = [];

for (const product of products) {
  const stock = product.total_stock || 0;
  const safetyStock = Math.max(
    product.safety_stock || 0,
    Math.floor(stock * SAFETY_STOCK_PERCENT)
  );
  const available = Math.max(0, stock - safetyStock);

  for (const [platform, ratio] of Object.entries(ALLOCATION)) {
    const allocated = Math.floor(available * ratio);
    syncTasks.push({
      sku: product.sku,
      platform,
      stock_to_sync: allocated,
      safety_stock: safetyStock,
      total_stock: stock,
      sync_time: new Date().toISOString()
    });
  }
}

return syncTasks.map(task => ({ json: task }));

// === AGGREGATE SYNC RESULTS ===
const results = $input.all().map(i => i.json);
const success = results.filter(r => r.statusCode >= 200 && r.statusCode < 300).length;
const failed = results.length - success;

return [{
  json: {
    total: results.length,
    success,
    failed,
    synced_at: new Date().toISOString(),
    summary: `${success}/${results.length} SKUs synced`
  }
}];

