// === FORMAT DAILY REPORT ===
const data = $input.item.json;
const platforms = data.by_platform || {};

let msg = `📊 Daily Report - ${new Date().toLocaleDateString('th-TH')}`;
msg += `\n${'─'.repeat(28)}`;
msg += `\n🛒 Orders: ${data.total_orders || 0}`;
msg += `\n💰 Revenue: ฿${(data.total_revenue || 0).toLocaleString()}`;
msg += `\n${'─'.repeat(28)}`;

for (const [platform, info] of Object.entries(platforms)) {
  const emoji = { shopee: '🟠', lazada: '🔵', tiktok: '⚫', facebook: '🔷' }[platform] || '⚪';
  msg += `\n${emoji} ${platform.toUpperCase()}`;
  msg += `\n   Orders: ${info.orders || 0} | Revenue: ฿${(info.revenue || 0).toLocaleString()}`;
}

msg += `\n${'─'.repeat(28)}`;
msg += `\n🕐 Generated: ${new Date().toISOString()}`;

return [{ json: { message: msg, type: 'daily' } }];

// === FORMAT WEEKLY REPORT ===
const data = $input.item.json;
const platforms = data.by_platform || {};

let msg = `📈 Weekly Report`;
msg += `\n${'═'.repeat(28)}`;
msg += `\n🛒 Total Orders: ${data.total_orders || 0}`;
msg += `\n💰 Total Revenue: ฿${(data.total_revenue || 0).toLocaleString()}`;
msg += `\n📦 Avg Order Value: ฿${data.total_orders ? Math.round((data.total_revenue || 0) / data.total_orders).toLocaleString() : 0}`;
msg += `\n${'═'.repeat(28)}`;

for (const [platform, info] of Object.entries(platforms)) {
  const emoji = { shopee: '🟠', lazada: '🔵', tiktok: '⚫', facebook: '🔷' }[platform] || '⚪';
  msg += `\n${emoji} ${platform.toUpperCase()}`;
  msg += `\n   Orders: ${info.orders || 0}`;
  msg += `\n   Revenue: ฿${(info.revenue || 0).toLocaleString()}`;
  msg += `\n   Top SKU: ${info.top_sku || 'N/A'}`;
}

// Low stock alerts
if (data.low_stock && data.low_stock.length > 0) {
  msg += `\n\n⚠️ LOW STOCK ALERTS`;
  msg += `\n${'─'.repeat(28)}`;
  for (const item of data.low_stock) {
    msg += `\n🔴 ${item.sku}: ${item.stock} left`;
  }
}

msg += `\n${'═'.repeat(28)}`;
msg += `\n🕐 Generated: ${new Date().toISOString()}`;

return [{ json: { message: msg, type: 'weekly' } }];

// === FORMAT ERROR DETAILS ===
const error = $input.item.json || {};
const msg = `🚨 SYSTEM ERROR` +
  `\nError: ${error.execution?.error?.message || error.message || 'Unknown'}` +
  `\nNode: ${error.execution?.lastNodeExecuted || error.node || 'N/A'}` +
  `\nWorkflow: ${error.workflow?.name || 'Factory Automation'}` +
  `\nTime: ${new Date().toISOString()}`;
return { json: { message: msg, error_details: error } };
